        src_folio = page_folio(src_page);

        if (!(dst_pfns[i] & 1) || !dst_folio) { // MIGRATE_PFN_MIGRATED is replaced by 1 as a placeholder
            if (dst_folio) {
                folio_unlock(dst_folio);
                folio_put(dst_folio);
